import Foundation
import Compression

enum EPUBConstants {
    static let mimetype = Data("application/epub+zip".utf8)
    static let containerPath = "META-INF/container.xml"
    static let opfMediaType = "application/oebps-package+xml"
    static let maxSendBytes = 200 * 1024 * 1024
    static let maxHTMLEntryBytes = 30 * 1024 * 1024
    static let maxHTMLFileCount = 300
    static let htmlSuffixes: Set<String> = ["htm", "html", "xhtml"]
    static let fontSuffixes: Set<String> = ["otf", "ttf", "woff", "woff2"]
    static let knownMediaTypes: [String: String] = [
        "css": "text/css",
        "gif": "image/gif",
        "htm": "application/xhtml+xml",
        "html": "application/xhtml+xml",
        "jpeg": "image/jpeg",
        "jpg": "image/jpeg",
        "js": "text/javascript",
        "ncx": "application/x-dtbncx+xml",
        "otf": "font/otf",
        "png": "image/png",
        "svg": "image/svg+xml",
        "ttf": "font/ttf",
        "woff": "font/woff",
        "woff2": "font/woff2",
        "xhtml": "application/xhtml+xml",
    ]
}

struct EPUBArchiveEntry {
    var name: String
    var data: Data
    var isStored: Bool
}

enum EPUBInspection {
    static func readEntries(from url: URL) throws -> (orderedNames: [String], entries: [String: EPUBArchiveEntry]) {
        guard let archive = ArchiveReader(url: url) else {
            throw DomainError.repair("Input EPUB is not a valid ZIP archive: \(url.lastPathComponent)")
        }
        return try archive.readAll()
    }

    static func isUnsafeArchivePath(_ value: String) -> Bool {
        if value.contains("\\") || value.hasPrefix("/") { return true }
        let parts = value.split(separator: "/", omittingEmptySubsequences: false).map(String.init)
        if parts.contains(where: { $0 == ".." || $0 == "." || $0.isEmpty }) { return true }
        return false
    }

    static func normalizeArchivePath(_ value: String) throws -> String {
        if isUnsafeArchivePath(value) {
            throw DomainError.repair("EPUB contains an unsafe path: \(value)")
        }
        let normalized = (value as NSString).standardizingPath
            .trimmingCharacters(in: CharacterSet(charactersIn: "/"))
        if normalized.isEmpty || isUnsafeArchivePath(normalized) {
            throw DomainError.repair("EPUB contains an unsafe path: \(value)")
        }
        return normalized.replacingOccurrences(of: "//", with: "/")
    }

    static func localName(_ tag: String) -> String {
        if let idx = tag.lastIndex(of: "}") {
            return String(tag[tag.index(after: idx)...])
        }
        return tag
    }

    static func packagePath(fromContainer data: Data) -> String? {
        guard let xml = String(data: data, encoding: .utf8) else { return nil }
        // Lightweight parse for full-path attribute on rootfile
        guard let rootfileRange = xml.range(of: "<rootfile", options: .caseInsensitive) else { return nil }
        let slice = xml[rootfileRange.lowerBound...]
        guard let fullPathKey = slice.range(of: "full-path=\"") ?? slice.range(of: "full-path='") else { return nil }
        let quote = slice[fullPathKey.upperBound...] .first == "\"" ? "\"" : "'"
        // Actually after full-path= the quote is the last char of the matched prefix - handle both
        let after = slice[fullPathKey.upperBound...]
        guard let end = after.firstIndex(of: after.first == "\"" || after.first == "'" ? after.first! : "\"") else {
            // simpler regex-like scan
            return extractAttribute(named: "full-path", in: String(slice.prefix(300)))
        }
        _ = end
        return extractAttribute(named: "full-path", in: String(slice.prefix(400)))
    }

    static func extractAttribute(named name: String, in text: String) -> String? {
        let patterns = ["\(name)=\"", "\(name)='"]
        for pattern in patterns {
            guard let start = text.range(of: pattern) else { continue }
            let rest = text[start.upperBound...]
            let quote = pattern.last!
            guard let end = rest.firstIndex(of: quote) else { continue }
            let value = String(rest[..<end])
            if !value.isEmpty { return value }
        }
        return nil
    }

    static func resolveHref(opfPath: String, href: String) throws -> String {
        if href.contains("://") {
            throw DomainError.repair("OPF manifest href is external: \(href)")
        }
        let cleaned = href.split(separator: "#", maxSplits: 1, omittingEmptySubsequences: false).first
            .map(String.init) ?? href
        let decoded = cleaned.removingPercentEncoding ?? cleaned
        if decoded.isEmpty {
            throw DomainError.repair("OPF manifest href is empty: \(opfPath)")
        }
        if isUnsafeArchivePath(decoded) {
            throw DomainError.repair("OPF manifest href is unsafe: \(href)")
        }
        let dir = (opfPath as NSString).deletingLastPathComponent
        let joined = dir.isEmpty ? decoded : (dir as NSString).appendingPathComponent(decoded)
        let normalized = try normalizeArchivePath(joined.replacingOccurrences(of: "\\", with: "/"))
        return normalized
    }

    static func knownMediaType(for path: String) -> String? {
        let ext = (path as NSString).pathExtension.lowercased()
        return EPUBConstants.knownMediaTypes[ext]
    }
}

/// Minimal ZIP reader for stored/deflated entries using Compression framework.
final class ArchiveReader {
    private let data: Data

    init?(url: URL) {
        guard let data = try? Data(contentsOf: url), data.count >= 22 else { return nil }
        // EOCD signature check loosely
        self.data = data
    }

    func readAll() throws -> (orderedNames: [String], entries: [String: EPUBArchiveEntry]) {
        var ordered: [String] = []
        var map: [String: EPUBArchiveEntry] = [:]
        var offset = 0
        let bytes = [UInt8](data)

        while offset + 30 <= bytes.count {
            // local file header signature 0x04034b50
            let sig = u32(bytes, offset)
            if sig != 0x04034b50 {
                break
            }
            let compression = u16(bytes, offset + 8)
            let compSize = Int(u32(bytes, offset + 18))
            let nameLen = Int(u16(bytes, offset + 26))
            let extraLen = Int(u16(bytes, offset + 28))
            let nameStart = offset + 30
            let nameEnd = nameStart + nameLen
            guard nameEnd + extraLen + compSize <= bytes.count else {
                throw DomainError.repair("Input EPUB contains unreadable ZIP entries.")
            }
            let nameData = Data(bytes[nameStart..<nameEnd])
            let name = String(data: nameData, encoding: .utf8) ?? ""
            let dataStart = nameEnd + extraLen
            let dataEnd = dataStart + compSize
            let payload = Data(bytes[dataStart..<dataEnd])
            offset = dataEnd

            if name.hasSuffix("/") { continue }
            let normalized = name.replacingOccurrences(of: "\\", with: "/")
            let uncompressed: Data
            if compression == 0 {
                uncompressed = payload
            } else if compression == 8 {
                uncompressed = try inflate(payload)
            } else {
                throw DomainError.repair("Unsupported ZIP compression method for entry: \(name)")
            }
            ordered.append(normalized)
            map[normalized] = EPUBArchiveEntry(name: normalized, data: uncompressed, isStored: compression == 0)
        }

        if map.isEmpty {
            throw DomainError.repair("EPUB archive has no content entries.")
        }
        return (ordered, map)
    }

    private func u16(_ bytes: [UInt8], _ offset: Int) -> UInt16 {
        UInt16(bytes[offset]) | (UInt16(bytes[offset + 1]) << 8)
    }

    private func u32(_ bytes: [UInt8], _ offset: Int) -> UInt32 {
        UInt32(bytes[offset])
            | (UInt32(bytes[offset + 1]) << 8)
            | (UInt32(bytes[offset + 2]) << 16)
            | (UInt32(bytes[offset + 3]) << 24)
    }

    private func inflate(_ data: Data) throws -> Data {
        let bufferSize = max(data.count * 4, 64 * 1024)
        var destination = Data(count: bufferSize)
        let result = try data.withUnsafeBytes { (src: UnsafeRawBufferPointer) -> Int in
            try destination.withUnsafeMutableBytes { (dst: UnsafeMutableRawBufferPointer) -> Int in
                guard let srcBase = src.bindMemory(to: UInt8.self).baseAddress,
                      let dstBase = dst.bindMemory(to: UInt8.self).baseAddress else {
                    throw DomainError.repair("Failed to inflate ZIP entry.")
                }
                var sourceSize = data.count
                var destSize = bufferSize
                let status = compression_decode_buffer(
                    dstBase,
                    destSize,
                    srcBase,
                    sourceSize,
                    nil,
                    COMPRESSION_ZLIB
                )
                // raw deflate often needs COMPRESSION_ZLIB with zlib wrapper; ZIP uses raw deflate.
                // Try raw deflate algorithm:
                if status == 0 {
                    var stream = compression_stream(
                        dst_ptr: dstBase,
                        dst_size: destSize,
                        src_ptr: srcBase,
                        src_size: sourceSize,
                        state: nil
                    )
                    var streamPtr = stream
                    let initStatus = compression_stream_init(&streamPtr, COMPRESSION_STREAM_DECODE, COMPRESSION_ZLIB)
                    guard initStatus == COMPRESSION_STATUS_OK else {
                        throw DomainError.repair("Failed to inflate ZIP entry.")
                    }
                    defer { compression_stream_destroy(&streamPtr) }
                    streamPtr.src_ptr = srcBase
                    streamPtr.src_size = sourceSize
                    streamPtr.dst_ptr = dstBase
                    streamPtr.dst_size = destSize
                    let flags = Int32(COMPRESSION_STREAM_FINALIZE.rawValue)
                    let decodeStatus = compression_stream_process(&streamPtr, flags)
                    guard decodeStatus == COMPRESSION_STATUS_END || decodeStatus == COMPRESSION_STATUS_OK else {
                        throw DomainError.repair("Failed to inflate ZIP entry.")
                    }
                    return destSize - streamPtr.dst_size
                }
                return status
            }
        }
        if result == 0 {
            // Fallback: use Process to ditto/unzip? Keep failure explicit.
            throw DomainError.repair("Failed to inflate ZIP entry.")
        }
        destination.count = result
        return destination
    }
}

